import React, { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { useMusic } from '../../context/MusicContext';
import { ListPlus, Play, Music, CheckCircle2, Circle, X, Library as LibraryIcon } from 'lucide-react';

const Home = () => {
  const navigate = useNavigate();
  const { playMusic } = useMusic();
  
  // --- STATES ---
  const [songs, setSongs] = useState([]);
  const [playlists, setPlaylists] = useState([]);
  const [isSelecting, setIsSelecting] = useState(false);
  const [newPlaylistTitle, setNewPlaylistTitle] = useState("");
  const [selectedSongIds, setSelectedSongIds] = useState([]);
  const [loading, setLoading] = useState(true);

  const loggedInUser = JSON.parse(localStorage.getItem('user'));
  const userId = loggedInUser?._id || loggedInUser?.id;

  // --- FETCH DATA ---
  const fetchSongs = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs');
      setSongs(res.data);
    } catch (err) { console.error("Lỗi tải bài hát:", err); }
  };

  const fetchUserPlaylists = useCallback(async () => {
    if (!userId) return;
    try {
      const res = await axios.get(`http://localhost:5000/api/playlists/user/${userId}`);
      setPlaylists(res.data);
    } catch (err) { console.error("Lỗi tải playlist:", err); }
    finally { setLoading(false); }
  }, [userId]);

  useEffect(() => {
    fetchSongs();
    fetchUserPlaylists();
  }, [fetchUserPlaylists]);

  // --- LOGIC TẠO PLAYLIST ---
  
  // Bước 1: Mở chế độ chọn nhạc
  const startCreating = () => {
    const title = prompt("Nhập tên playlist mới:");
    if (title && title.trim() !== "") {
      setNewPlaylistTitle(title);
      setIsSelecting(true);
      setSelectedSongIds([]); // Reset danh sách chọn
    }
  };

  // Bước 2: Lưu vào Database
  const handleSavePlaylist = async () => {
    if (!userId) return alert("Vui lòng đăng nhập!");
    
    // Bạn có thể cho phép tạo playlist rỗng hoặc bắt buộc chọn bài
    // Ở đây mình cho phép tạo dù chưa chọn bài nào
    try {
      const payload = {
        title: newPlaylistTitle,
        userId: userId,
        songs: selectedSongIds // Gửi mảng ID bài hát lên (Backend dùng field 'songs')
      };

      const res = await axios.post('http://localhost:5000/api/playlists', payload);

      if (res.status === 201 || res.status === 200) {
        alert("Tạo playlist thành công!");
        setIsSelecting(false);
        setNewPlaylistTitle("");
        setSelectedSongIds([]);
        
        // CẬP NHẬT STATE NGAY LẬP TỨC để thấy số bài hát mới
        setPlaylists(prev => [...prev, res.data]); 
        
        // Hoặc gọi lại hàm fetch để chắc chắn dữ liệu đồng bộ
        fetchUserPlaylists();
      }
    } catch (err) {
      console.error("Lỗi lưu playlist:", err);
      alert("Không thể lưu playlist. Vui lòng thử lại.");
    }
  };

  if (loading) return <div style={{textAlign:'center', padding:'100px', color:'#fff', background:'#121212', minHeight:'100vh'}}>Đang tải...</div>;

  return (
    <div style={containerStyle}>
      
      {/* THANH CÔNG CỤ KHI CHỌN NHẠC */}
      {isSelecting && (
        <div style={selectionBar}>
          <div style={{display:'flex', alignItems:'center', gap:'15px'}}>
            <ListPlus size={24}/>
            <span>Đang tạo: <b>{newPlaylistTitle}</b> ({selectedSongIds.length} bài hát được chọn)</span>
          </div>
          <div style={{ display: 'flex', gap: '10px' }}>
            <button onClick={handleSavePlaylist} style={btnConfirm}>HOÀN TẤT</button>
            <button onClick={() => setIsSelecting(false)} style={btnCancel}><X size={20}/></button>
          </div>
        </div>
      )}

      <header style={headerStyle}>
        <h1 style={logoStyle}><Music size={36} color="#1db954"/> IAMNHAC</h1>
        {!isSelecting && (
          <button onClick={startCreating} style={btnCreate}>+ TẠO PLAYLIST MỚI</button>
        )}
      </header>

      {/* DANH SÁCH PLAYLIST CỦA BẠN */}
      {playlists.length > 0 && !isSelecting && (
        <section style={{ marginBottom: '50px' }}>
          <h2 style={sectionTitle}><LibraryIcon size={24} color="#1db954"/> Thư viện của bạn</h2>
          <div style={playlistGrid}>
            {playlists.map(pl => (
              <div key={pl._id} style={plCard} onClick={() => navigate(`/playlist/${pl._id}`)}>
                <div style={plIcon}><Music color="#fff" size={40} strokeWidth={1}/></div>
                <div style={plTitle}>{pl.title}</div>
                <div style={plCount}>{pl.songs?.length || 0} bài hát</div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* DANH SÁCH KHÁM PHÁ NHẠC */}
      <section>
        <h2 style={sectionTitle}>{isSelecting ? "Chọn bài hát để thêm vào playlist" : "Khám phá nhạc mới"}</h2>
        <div style={songGrid}>
          {songs.map((song, index) => {
            const isSelected = selectedSongIds.includes(song._id);
            return (
              <div key={song._id} style={sCard(isSelected)} onClick={() => {
                if(isSelecting) {
                  setSelectedSongIds(prev => 
                    prev.includes(song._id) ? prev.filter(id => id !== song._id) : [...prev, song._id]
                  );
                } else {
                  playMusic(songs, index);
                }
              }}>
                <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '10px' }}>
                  <img src={`http://localhost:5000${song.imageUrl}`} style={sImg} alt={song.title} />
                  {isSelecting ? (
                    <div style={checkOverlay}>
                      {isSelected ? <CheckCircle2 color="#fff" fill="#1db954" size={30}/> : <Circle color="#fff" size={30}/>}
                    </div>
                  ) : (
                    <div className="play-overlay" style={playIconOverlay}><Play fill="#fff" size={20}/></div>
                  )}
                </div>
                <div style={songInfo}>
                  <div style={songTitle}>{song.title}</div>
                  <div style={songArtist}>{song.artist}</div>
                </div>
              </div>
            );
          })}
        </div>
      </section>
    </div>
  );
};

